def top_k(nums, k):
    if not nums or k <= 0:
        return []
    elif len(nums) < k:
        nums.sort(reverse=True)
        return nums[:k]
    else:
        heapsort = [None]*k
        for n in nums:
            i = k - 1
            while i > 0 and heapsort[i] < n:
                heapsort[i+1] = heapsort[i]
                i -= 1
            heapsort[i+1] = n
        return heapsort
